 87→            HjSystemProperty.eventLogging.setProperty(true);
 88→        }
 89→
 90→        launchHabaneroApp(() -> {
 91→            async(() -> {
 92→                parScore[0] = parConstructor.create(xLength, yLength).scoreSequences(xInput, yInput);
 93→            });
 94→        }, () -> {
 95→            if (checkAbstractMetrics) {
 96→                HjMetrics metrics = abstractMetrics();
 97→                parCPL[0] = metrics.criticalPathLength();
 98→                parWork[0] = metrics.totalWork();
 99→            }
100→        });
101→
102→        if (checkAbstractMetrics) {
103→            System.out.println("Homework3Test.kernel: seqScore = " + seqScore[0] + ", parScore = " + parScore[0] +
104→                    ", parWork = " + parWork[0] + ", parCPL = " + parCPL[0]);
105→        } else {
106→            System.out.println("Homework3Test.kernel: seqScore = " + seqScore[0] + ", parScore = " + parScore[0]);
107→        }
108→
109→        assertTrue("Scores do not match! Sequential = " + seqScore[0] + ", Parallel = " + parScore[0],
110→                seqScore[0] == parScore[0]);
111→        if (checkAbstractMetrics) {
112→            assertTrue("Work does not match! Sequential = " + (xLength * yLength) + ", Parallel = " + parWork[0],
113→                    (xLength * yLength) == parWork[0]);
114→            assertTrue("CPL for ideal parallel version should be " + (xLength + yLength - 1) + " for xLength = " +
115→                    xLength + ", yLength = " + yLength + ", but got " + parCPL[0] + " from parallel implementation",
116→                    (xLength + yLength - 1) == parCPL[0]);
117→        }
118→
119→        System.out.println("Test successful for size " + xLength + " and " + yLength);
120→    }
121→}
