 5→/**
 6→ * Any method of scoring the sequential alignment of two DNA strings.
 7→ *
 8→ * @author Derek
 9→ */
10→public abstract class AbstractDnaScoring {
11→
12→    // scoring matrix
13→    /*
14→           _  A  C  G  T
15→        ------------------
16→        _ |-8 -2 -2 -2 -2
17→        A |-4  5  2  2  2
18→        C |-4  2  5  2  2
19→        G |-4  2  2  5  2
20→        T |-4  2  2  2  5
21→    */
22→    protected static final int[][] M = new int[][]{{-8, -2, -2, -2, -2},
23→        {-4, 5, 2, 2, 2},
24→        {-4, 2, 5, 2, 2},
25→        {-4, 2, 2, 5, 2},
26→        {-4, 2, 2, 2, 5}};
27→
28→    /**
29→     * Helper method for getting the index of character in scoring matrix.
30→     *
31→     * @param inputChar The character to search for.
32→     * @return The index of the requested character in the matrix.
33→     */
34→    protected int charMap(final char inputChar) {
35→        switch (inputChar) {
36→            case '_':
37→                return 0;
38→            case 'A':
39→            case 'a':
40→                return 1;
41→            case 'C':
42→            case 'c':
43→                return 2;
44→            case 'G':
45→            case 'g':
46→                return 3;
47→            case 'T':
48→            case 't':
49→                return 4;
50→            default:
51→                throw new IllegalArgumentException("Invalid DNA character: " + inputChar);
52→        }
53→    }
54→
55→    /**
56→     * Get score assigned for alignment of two letters.
57→     *
58→     * @param iVal the first index in the scoring matrix
59→     * @param jVal the second index in the scoring matrix
60→     * @return the corresponding value in the matrix
61→     */
62→    protected int getScore(final int iVal, final int jVal) {
63→        return M[iVal][jVal];
64→    }
65→
66→    /**
67→     * Helper method for printing out a two dimensional int array, can be useful for debugging.
68→     *
69→     * @param matrix The desired int matrix to be printed.
70→     */
71→    public void printMatrix(final int[][] matrix) {
72→        for (int i = 0; i < matrix.length; i++) {
73→            for (int j = 0; j < matrix[0].length; j++) {
74→                System.out.print(matrix[i][j] + " ");
75→            }
76→            System.out.println();
77→        }
78→        System.out.println("--------------------------------");
79→    }
80→
81→    /**
82→     * Compute the solution matrix and return the alignment score of two DNA sequences. This one is done sequentially.
83→     *
84→     * @param x The first sequence to be compared.
85→     * @param y The second sequence to be compared.
86→     * @return The alignment score between them
87→     */
88→    public abstract int scoreSequences(String x, String y) throws SuspendableException;
89→}
